    });

    return (
        <div className="ui segments">
            <div className="ui segment grid-top top-cover"></div>
            <div className="ui segment choices">
                <button className="circular ui grid-top inverted right labeled icon purple button" onClick={()=>SetButtonClick({web:true})}><i className="right arrow icon"></i>Front/Back-end Developer</button>
                <button className="circular ui grid-bottom inverted right labeled icon purple button" onClick={()=>SetButtonClick({software:true})}><i className="right arrow icon"></i>Software Engineer</button>
            </div>
            <div className="bottom-cover-div">
            <div className="ui segment grid-bottom bottom-cover"></div>
            </div>
        </div>
    )
};
export default Cover;
